# scripts/validate_runbook_links.py — run in CI on alert rule changes
import os, re, sys, requests
import yaml
from pathlib import Path

ALERTS_DIR  = Path("alerts")
TIMEOUT     = 8
FOLLOW_REDIRECTS = False  # runbooks must be at their canonical URL, not redirected


def extract_runbook_urls(yaml_path: Path) -> list[tuple[str, str]]:
    """Returns list of (alertname, url) pairs from a rule file."""
    content = yaml.safe_load(yaml_path.read_text())
    results = []
    for group in content.get("groups", []):
        for rule in group.get("rules", []):
            name = rule.get("alert", "?")
            url = rule.get("annotations", {}).get("runbook")
            if url:
                results.append((name, url))
    return results


def check_url(alertname: str, url: str) -> bool:
    try:
        resp = requests.head(url, timeout=TIMEOUT, allow_redirects=FOLLOW_REDIRECTS)
        if resp.status_code in (200, 405):  # 405 = HEAD not allowed, page exists
            return True
        print(f"[FAIL] {alertname}: {url} → HTTP {resp.status_code}")
        return False
    except requests.RequestException as e:
        print(f"[ERROR] {alertname}: {url} → {e}")
        return False


if __name__ == "__main__":
    failures = []
    missing = []
    for path in sorted(ALERTS_DIR.glob("**/*.yaml")):
        pairs = extract_runbook_urls(path)
        for alertname, url in pairs:
            if not check_url(alertname, url):
                failures.append((alertname, url))
        # Find alerts with NO runbook annotation
        content = yaml.safe_load(path.read_text())
        for group in content.get("groups", []):
            for rule in group.get("rules", []):
                if "alert" in rule and "runbook" not in rule.get("annotations", {}):
                    missing.append((rule["alert"], str(path)))

    if missing:
        print(f"\n{len(missing)} alert(s) missing runbook annotation:")
        for name, path in missing:
            print(f"  {name} in {path}")

    if failures:
        print(f"\n{len(failures)} runbook link(s) broken:")
        for name, url in failures:
            print(f"  {name} → {url}")

    if missing or failures:
        sys.exit(1)
    print(f"All runbook links valid.")
